        var valueStr = decimals.HasValue ? scaledValue.ToString($"F{decimals}") : scaledValue.ToString("G4");

        var suffix = formats.HasFlag(MetricFormat.UseSymbol)
            ? SymbolStrings[symbol]
            : string.Concat(" ", GetPrefixName(symbol, formats));

