1. using System.Collections.Frozen;
2. 
3. namespace Textualizer;
4. 
5. /// <summary>
6. /// Defines formatting options for metric numeral representations.
7. /// </summary>
8. [Flags]
9. public enum MetricFormat
10. {
11.     /// <summary>No special formatting applied.</summary>
12.     None = 0,
13. 
14.     /// <summary>Use the unit symbol instead of the full name (e.g., "k" instead of "kilo").</summary>
15.     UseSymbol = 1,
16. 
17.     /// <summary>Use short scale names (e.g., "billion" vs "milliard").</summary>
18.     UseShortScale = 2,
19. 
20.     /// <summary>Include the base unit name in the output.</summary>
21.     IncludeBaseUnit = 4
22. }
23. 
24. /// <summary>
25. /// Represents a metric unit prefix with its name, symbol, and scale words.
26. /// </summary>
27. internal readonly struct UnitPrefix : IEquatable<UnitPrefix>
28. {
29.     /// <summary>Gets the full name of this prefix (e.g., "kilo", "mega").</summary>
30.     public string Name { get; }
31. 
32.     /// <summary>Gets the short scale word (e.g., "thousand", "million").</summary>
33.     public string ShortScaleWord { get; }
34. 
35.     /// <summary>Gets the long scale word, falling back to short scale if not specified.</summary>
36.     public string LongScaleWord { get; }
37. 
38.     /// <summary>
39.     /// Initializes a new instance of the <see cref="UnitPrefix"/> struct.
40.     /// </summary>
41.     /// <param name="name">The prefix name.</param>
42.     /// <param name="shortScaleWord">The short scale word.</param>
43.     /// <param name="longScaleWord">The long scale word, or null to use short scale.</param>
44.     public UnitPrefix(string name, string shortScaleWord, string? longScaleWord = null)
45.     {
46.         Name = name;
47.         ShortScaleWord = shortScaleWord;
48.         LongScaleWord = longScaleWord ?? shortScaleWord;
49.     }
50. 
51.     public bool Equals(UnitPrefix other) =>
52.         Name == other.Name && ShortScaleWord == other.ShortScaleWord && LongScaleWord == other.LongScaleWord;
53. 
54.     public override bool Equals(object? obj) => obj is UnitPrefix other && Equals(other);
55. 
56.     public override int GetHashCode() => HashCode.Combine(Name, ShortScaleWord, LongScaleWord);
57. }
58. 
59. /// <summary>
60. /// Provides extension methods for converting numbers to and from metric numeral representations
61. /// (e.g., 1000 → "1k", "2.5M" → 2500000).
62. /// </summary>
63. public static class MetricNumeralExtensions
64. {
65.     private static readonly FrozenDictionary<char, UnitPrefix> UnitPrefixes =
66.         new Dictionary<char, UnitPrefix>
67.         {
68.             ['k'] = new("kilo", "thousand"),
69.             ['M'] = new("mega", "million"),
70.             ['G'] = new("giga", "billion", "milliard"),
71.             ['T'] = new("tera", "trillion", "billion"),
72.             ['P'] = new("peta", "quadrillion", "billiard"),
73.             ['E'] = new("exa", "quintillion", "trillion"),
74.             ['Z'] = new("zetta", "sextillion", "trilliard"),
75.             ['Y'] = new("yotta", "septillion", "quadrillion"),
76.             ['m'] = new("milli", "thousandth"),
77.             ['μ'] = new("micro", "millionth"),
78.             ['n'] = new("nano", "billionth", "milliardth"),
79.             ['p'] = new("pico", "trillionth", "billionth"),
80.             ['f'] = new("femto", "quadrillionth", "billiardth"),
81.             ['a'] = new("atto", "quintillionth", "trillionth"),
82.             ['z'] = new("zepto", "sextillionth", "trilliardth"),
83.             ['y'] = new("yocto", "septillionth", "quadrillionth"),
84.         }.ToFrozenDictionary();
85. 
86.     // Precomputed O(1) lookup from exponent to symbol, replacing the O(n) scan in GetSymbolForExponent
87.     private static readonly FrozenDictionary<int, char> ExponentToSymbol =
88.         new Dictionary<int, char>
89.         {
90.             [3] = 'k', [6] = 'M', [9] = 'G', [12] = 'T', [15] = 'P', [18] = 'E', [21] = 'Z', [24] = 'Y',
91.             [-3] = 'm', [-6] = 'μ', [-9] = 'n', [-12] = 'p', [-15] = 'f', [-18] = 'a', [-21] = 'z', [-24] = 'y',
92.         }.ToFrozenDictionary();
93. 
94.     // Precomputed O(1) lookup from prefix name to symbol, replacing the Aggregate+Replace pattern
95.     private static readonly FrozenDictionary<string, char> NameToSymbol =
96.         new Dictionary<string, char>
97.         {
98.             ["kilo"] = 'k', ["mega"] = 'M', ["giga"] = 'G', ["tera"] = 'T',
99.             ["peta"] = 'P', ["exa"] = 'E', ["zetta"] = 'Z', ["yotta"] = 'Y',
100.             ["milli"] = 'm', ["micro"] = 'μ', ["nano"] = 'n', ["pico"] = 'p',
101.             ["femto"] = 'f', ["atto"] = 'a', ["zepto"] = 'z', ["yocto"] = 'y',
102.         }.ToFrozenDictionary();
103. 
104.     // Precomputed powers of 10, avoiding Math.Pow allocations on every call
105.     private static readonly FrozenDictionary<int, double> PowersOf10 =
106.         new Dictionary<int, double>
107.         {
108.             [3] = 1e3, [6] = 1e6, [9] = 1e9, [12] = 1e12, [15] = 1e15, [18] = 1e18, [21] = 1e21, [24] = 1e24,
109.             [-3] = 1e-3, [-6] = 1e-6, [-9] = 1e-9, [-12] = 1e-12, [-15] = 1e-15, [-18] = 1e-18, [-21] = 1e-21, [-24] = 1e-24,
110.         }.ToFrozenDictionary();
111. 
112.     // Cached single-char strings to avoid char.ToString() allocations
113.     private static readonly FrozenDictionary<char, string> SymbolStrings =
114.         new Dictionary<char, string>
115.         {
116.             ['k'] = "k", ['M'] = "M", ['G'] = "G", ['T'] = "T", ['P'] = "P", ['E'] = "E", ['Z'] = "Z", ['Y'] = "Y",
117.             ['m'] = "m", ['μ'] = "μ", ['n'] = "n", ['p'] = "p", ['f'] = "f", ['a'] = "a", ['z'] = "z", ['y'] = "y",
118.         }.ToFrozenDictionary();
119. 
120.     /// <summary>
121.     /// Converts a number to its metric representation using the specified formatting options.
122.     /// </summary>
123.     /// <param name="input">The number to convert.</param>
124.     /// <param name="formats">Formatting options controlling symbol vs name and scale.</param>
125.     /// <param name="decimals">Optional number of decimal places to round to.</param>
126.     /// <returns>A string with the metric representation (e.g., "1.5k" or "1.5 kilo").</returns>
127.     /// <example>
128.     /// <code>
129.     /// 1500.ToMetric() => "1.5k"
130.     /// 1500.ToMetric(MetricFormat.None) => "1.5 kilo"
131.     /// 2500000.ToMetric(MetricFormat.UseSymbol) => "2.5M"
132.     /// </code>
133.     /// </example>
134.     public static string ToMetric(this double input, MetricFormat formats = MetricFormat.UseSymbol, int? decimals = null)
135.     {
136.         if (double.IsNaN(input) || double.IsInfinity(input))
137.         {
138.             return input.ToString();
139.         }
140. 
141.         if (Math.Abs(input) < 1e-24)
142.         {
143.             return "0";
144.         }
145. 
146.         var isNegative = input < 0;
147.         input = Math.Abs(input);
148. 
149.         var exponent = (int)Math.Floor(Math.Log10(input));
150.         var metricExponent = exponent - (exponent % 3);
151. 
152.         if (metricExponent == 0)
153.         {
154.             var formatted = decimals.HasValue ? input.ToString($"F{decimals}") : input.ToString("G");
155.             return isNegative ? string.Concat("-", formatted) : formatted;
156.         }
157. 
158.         if (!ExponentToSymbol.TryGetValue(metricExponent, out var symbol))
159.         {
160.             var fallback = input.ToString("G");
161.             return isNegative ? string.Concat("-", fallback) : fallback;
162.         }
163. 
164.         var scaledValue = input / PowersOf10[metricExponent];
165.         var valueStr = decimals.HasValue ? scaledValue.ToString($"F{decimals}") : scaledValue.ToString("G4");
166. 
167.         var suffix = formats.HasFlag(MetricFormat.UseSymbol)
168.             ? SymbolStrings[symbol]
169.             : string.Concat(" ", GetPrefixName(symbol, formats));
170. 
171.         return isNegative ? string.Concat("-", valueStr, suffix) : string.Concat(valueStr, suffix);
172.     }
173. 
174.     /// <summary>
175.     /// Converts a metric string representation back to a number.
176.     /// </summary>
177.     /// <param name="input">The metric string to parse (e.g., "1.5k", "2.5 mega").</param>
178.     /// <returns>The numeric value represented by the metric string.</returns>
179.     /// <exception cref="ArgumentException">Thrown when the input is not a valid metric representation.</exception>
180.     /// <example>
181.     /// <code>
182.     /// "1.5k".FromMetric() => 1500
183.     /// "2.5M".FromMetric() => 2500000
184.     /// "100m".FromMetric() => 0.1
185.     /// </code>
186.     /// </example>
187.     public static double FromMetric(this string input)
188.     {
189.         ArgumentException.ThrowIfNullOrWhiteSpace(input);
190. 
191.         input = input.Trim();
192.         if (double.TryParse(input, out var directParse))
193.         {
194.             return directParse;
195.         }
196. 
197.         // Try symbol-based parsing first
198.         var lastChar = input[^1];
199.         if (UnitPrefixes.TryGetValue(lastChar, out _))
200.         {
201.             var numericPart = input[..^1].Trim();
202.             if (double.TryParse(numericPart, out var value))
203.             {
204.                 var exponent = GetExponentForSymbol(lastChar);
205.                 return value * PowersOf10[exponent];
206.             }
207.         }
208. 
209.         // Try name-based parsing: find and replace only the matching prefix name
210.         if (TryReplaceNameWithSymbol(input, out var converted))
211.         {
212.             return converted.FromMetric();
213.         }
214. 
215.         throw new ArgumentException($"Invalid metric numeral: '{input}'", nameof(input));
216.     }
217. 
218.     /// <summary>
219.     /// Determines whether the given string is a valid metric numeral.
220.     /// </summary>
221.     /// <param name="input">The string to validate.</param>
222.     /// <returns>true if the string can be parsed as a metric numeral; otherwise, false.</returns>
223.     public static bool IsValidMetricNumeral(this string input)
224.     {
225.         if (string.IsNullOrWhiteSpace(input))
226.         {
227.             return false;
228.         }
229. 
230.         input = input.Trim();
231.         if (double.TryParse(input, out _))
232.         {
233.             return true;
234.         }
235. 
236.         var index = input.Length - 1;
237.         var last = input[index];
238.         var isSymbol = UnitPrefixes.ContainsKey(last);
239.         return isSymbol && double.TryParse(input[..index], out _);
240.     }
241. 
242.     /// <summary>
243.     /// Tries to find a metric prefix name in the input and replace it with its symbol.
244.     /// Returns false if no prefix name was found (zero allocations in that case).
245.     /// </summary>
246.     private static bool TryReplaceNameWithSymbol(string input, out string result)
247.     {
248.         foreach (var kvp in NameToSymbol)
249.         {
250.             var idx = input.IndexOf(kvp.Key, StringComparison.Ordinal);
251.             if (idx >= 0)
252.             {
253.                 result = string.Concat(input.AsSpan(0, idx), SymbolStrings[kvp.Value], input.AsSpan(idx + kvp.Key.Length));
254.                 return true;
255.             }
256.         }
257. 
258.         result = input;
259.         return false;
260.     }
261. 
262.     private static int GetExponentForSymbol(char symbol) =>
263.         symbol switch
264.         {
265.             'k' => 3, 'M' => 6, 'G' => 9, 'T' => 12, 'P' => 15, 'E' => 18, 'Z' => 21, 'Y' => 24,
266.             'm' => -3, 'μ' => -6, 'n' => -9, 'p' => -12, 'f' => -15, 'a' => -18, 'z' => -21, 'y' => -24,
267.             _ => 0
268.         };
269. 
270.     private static string GetPrefixName(char symbol, MetricFormat formats)
271.     {
272.         if (!UnitPrefixes.TryGetValue(symbol, out var prefix))
273.         {
274.             return SymbolStrings.TryGetValue(symbol, out var s) ? s : symbol.ToString();
275.         }
276. 
277.         return formats.HasFlag(MetricFormat.UseShortScale) ? prefix.ShortScaleWord : prefix.LongScaleWord;
278.     }
279. }
